// <auto-generated>
// Rust port of the .NET test-scheduler harness. Builds several test workflow
// trees under parent "folder" workflows and POSTs each parent's id to the
// scheduler's /api/scheduler/execute, exercising single, sequential, concurrent
// (same seq), and nested-folder dispatch. The scheduler then expands each tree
// and dispatches the Process leaves to their agents.
//
// Prereqs: a scheduler and at least one agent must be running and registered
// (Scheduler/Online, Agent/Online), and the schema must hold core.process /
// core.script rows named "test*".
// </auto-generated>
#![allow(dead_code)]
#![allow(clippy::all)]

use common::BaseObject;
use domain::server_node_core::{ServerNodeStatus, ServerNodeType};
use domain::workflow_core::{OnFailureAction, WorkflowType};
use logic::{object_exec_unchecked, LogicContext};
use persist::{DBPersist, Row};
use serde_json::json;

const MIN_DATE: &str = "1900-01-01T00:00:00";

struct TestContext {
    scheduler_url: String,
    agent_id: i64,
    process_ids: Vec<i64>,
}

fn main() {
    if let Err(e) = run() {
        eprintln!("test-scheduler: {}", e);
        std::process::exit(1);
    }
}

fn run() -> Result<(), String> {
    delete_existing()?;
    let ctx = load_context()?;
    test_single_job(&ctx)?;
    test_two_job(&ctx)?;
    test_four_job_concurrency(&ctx)?;
    test_nested(&ctx)?;
    println!("\ntest-scheduler: all workflows dispatched");
    Ok(())
}

fn delete_existing() -> Result<(), String> {
    println!("test-scheduler: deleting existing test workflows...");
    DBPersist::exec_cmd(
        "DELETE FROM core.workflow WHERE name LIKE 'test-scheduler%'",
        "default",
    )
    .map_err(e2s)?;
    Ok(())
}

fn load_context() -> Result<TestContext, String> {
    let agent_rows = DBPersist::select(
        &format!(
            "SELECT * FROM core.server_node WHERE server_node_type_id = {} \
             and server_node_status_id = {} and is_active=1",
            ServerNodeType::Agent as i64,
            ServerNodeStatus::Online as i64
        ),
        "default",
    )
    .map_err(e2s)?;
    let agent_id = agent_rows
        .first()
        .map(|r| row_i64(r, "id"))
        .ok_or("no online agents found — start a scriptagent first")?;

    let proc_rows = DBPersist::select(
        "SELECT * FROM core.process WHERE script_id IN \
         (SELECT id FROM core.script WHERE name LIKE 'test%' AND is_active=1)",
        "default",
    )
    .map_err(e2s)?;
    let process_ids: Vec<i64> = proc_rows.iter().map(|r| row_i64(r, "id")).collect();
    if process_ids.is_empty() {
        return Err("no test processes found (core.process -> core.script name like 'test%')".to_string());
    }

    let sched_rows = DBPersist::select(
        &format!(
            "SELECT * FROM core.server_node WHERE server_node_type_id = {} \
             and server_node_status_id = {} and is_active=1",
            ServerNodeType::Scheduler as i64,
            ServerNodeStatus::Online as i64
        ),
        "default",
    )
    .map_err(e2s)?;
    let scheduler_url = sched_rows
        .first()
        .map(|r| row_str(r, "url"))
        .filter(|u| !u.is_empty())
        .ok_or("no online scheduler found — start the scheduler first")?;

    println!(
        "test-scheduler: agent {}, {} process(es), scheduler {}",
        agent_id,
        process_ids.len(),
        scheduler_url
    );
    Ok(TestContext { scheduler_url, agent_id, process_ids })
}

// ── tests ────────────────────────────────────────────────────────────────────

fn test_single_job(ctx: &TestContext) -> Result<(), String> {
    println!("\n=== Test 1: Single Job Workflow ===");
    let parent = insert_folder("test-scheduler-single-job", 0)?;
    insert_process("test-scheduler-single-job-process", parent, ctx.process_ids[0], ctx.agent_id, 10)?;
    dispatch(&ctx.scheduler_url, parent)
}

fn test_two_job(ctx: &TestContext) -> Result<(), String> {
    println!("\n=== Test 2: Two Job Workflow (Sequential) ===");
    if ctx.process_ids.len() < 2 {
        println!("  skipped (need >= 2 processes)");
        return Ok(());
    }
    let parent = insert_folder("test-scheduler-two-job", 0)?;
    insert_process("test-scheduler-two-job-process1", parent, ctx.process_ids[0], ctx.agent_id, 10)?;
    insert_process("test-scheduler-two-job-process2", parent, ctx.process_ids[1], ctx.agent_id, 20)?;
    dispatch(&ctx.scheduler_url, parent)
}

fn test_four_job_concurrency(ctx: &TestContext) -> Result<(), String> {
    println!("\n=== Test 3: Four Job Workflow with Concurrency ===");
    if ctx.process_ids.len() < 4 {
        println!("  skipped (need >= 4 processes)");
        return Ok(());
    }
    let parent = insert_folder("test-scheduler-four-job-concurrent", 0)?;
    insert_process("test-scheduler-four-job-process1", parent, ctx.process_ids[0], ctx.agent_id, 10)?;
    insert_process("test-scheduler-four-job-process2", parent, ctx.process_ids[1], ctx.agent_id, 20)?;
    insert_process("test-scheduler-four-job-process3", parent, ctx.process_ids[2], ctx.agent_id, 20)?;
    insert_process("test-scheduler-four-job-process4", parent, ctx.process_ids[3], ctx.agent_id, 30)?;
    dispatch(&ctx.scheduler_url, parent)
}

fn test_nested(ctx: &TestContext) -> Result<(), String> {
    println!("\n=== Test 4: Nested Workflow ===");
    if ctx.process_ids.len() < 2 {
        println!("  skipped (need >= 2 processes)");
        return Ok(());
    }
    let parent = insert_folder("test-scheduler-nested-parent", 0)?;
    let folder1 = insert_folder("test-scheduler-nested-child-folder1", parent)?;
    insert_process("test-scheduler-nested-child-process1", folder1, ctx.process_ids[0], ctx.agent_id, 10)?;
    let folder2 = insert_folder("test-scheduler-nested-child-folder2", parent)?;
    insert_process("test-scheduler-nested-child-process2", folder2, ctx.process_ids[1], ctx.agent_id, 10)?;
    dispatch(&ctx.scheduler_url, parent)
}

// ── workflow building + dispatch ─────────────────────────────────────────────

fn insert_folder(name: &str, parent_id: i64) -> Result<i64, String> {
    let mut wf = BaseObject::new();
    wf.set("name", json!(name));
    wf.set("workflow_type_id", json!(WorkflowType::Folder as i64));
    wf.set("parent_id", json!(parent_id));
    wf.set("is_active", json!(1));
    wf.set("last_start_time", json!(MIN_DATE));
    wf.set("last_end_time", json!(MIN_DATE));
    let id = insert_workflow(&wf)?;
    println!("  created folder workflow {} - {}", id, name);
    Ok(id)
}

fn insert_process(
    name: &str,
    parent_id: i64,
    process_id: i64,
    agent_id: i64,
    seq: i64,
) -> Result<i64, String> {
    let mut wf = BaseObject::new();
    wf.set("name", json!(name));
    wf.set("workflow_type_id", json!(WorkflowType::Process as i64));
    wf.set("parent_id", json!(parent_id));
    wf.set("process_id", json!(process_id));
    wf.set("server_node_id", json!(agent_id));
    wf.set("seq", json!(seq));
    wf.set("on_failure_action_id", json!(OnFailureAction::Stop as i64));
    wf.set("is_active", json!(1));
    wf.set("last_start_time", json!(MIN_DATE));
    wf.set("last_end_time", json!(MIN_DATE));
    let id = insert_workflow(&wf)?;
    println!("  created process workflow {} (seq {}) - {}", id, seq, name);
    Ok(id)
}

fn insert_workflow(record: &BaseObject) -> Result<i64, String> {
    let mut ctx = LogicContext::for_record(record.clone());
    object_exec_unchecked("workflow", "insert", &mut ctx).map_err(e2s)?;
    Ok(ctx.transaction.get("id").as_i64().unwrap_or(0))
}

fn dispatch(scheduler_url: &str, workflow_id: i64) -> Result<(), String> {
    let endpoint = format!("{}/api/scheduler/execute", scheduler_url.trim_end_matches('/'));
    println!("  -> dispatching parent workflow {} to {}", workflow_id, endpoint);
    ureq::post(&endpoint)
        .set("Content-Type", "application/json")
        .send_string(&workflow_id.to_string())
        .map(|_| ())
        .map_err(e2s)
}

// ── helpers ──────────────────────────────────────────────────────────────────

fn row_i64(row: &Row, key: &str) -> i64 {
    row.get(key).and_then(|v| v.as_i64()).unwrap_or(0)
}

fn row_str(row: &Row, key: &str) -> String {
    match row.get(key) {
        Some(serde_json::Value::String(s)) => s.clone(),
        Some(other) => other.to_string(),
        None => String::new(),
    }
}

fn e2s<E: std::fmt::Display>(e: E) -> String {
    e.to_string()
}
